.colonial-timeline {
  max-width: 800px;
  margin: var(--space-2xl) auto var(--space-lg);
  padding: var(--space-xl) var(--space-lg);
  background: var(--color-card-bg);
  border: 1px solid var(--color-card-border);
  border-radius: 6px;
  box-shadow: var(--shadow-card);
  text-align: center;
}

.colonial-timeline__title {
  font-family: var(--font-display);
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--color-text);
  margin-bottom: var(--space-xs);
}

.colonial-timeline__subtitle {
  font-family: var(--font-body);
  font-size: 0.78rem;
  font-weight: 400;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--color-text-muted);
  margin-bottom: var(--space-xl);
}

.colonial-timeline__track {
  position: relative;
  height: 4px;
  background: var(--color-sepia-mid);
  border-radius: 2px;
  margin: 2.5rem 1rem 3.5rem;
}

/* Animated progress bar */
.colonial-timeline__progress {
  position: absolute;
  top: 0;
  left: 0;
  height: 100%;
  width: 0;
  background: linear-gradient(90deg, var(--color-colonial), var(--color-sepia-dark));
  border-radius: 2px;
  animation: timeline-fill 2.5s var(--ease-out) forwards;
  animation-play-state: paused;
}

/* Start animation when parent becomes visible via IntersectionObserver */
.colonial-timeline.reveal--visible .colonial-timeline__progress {
  animation-play-state: running;
}

@keyframes timeline-fill {
  from { width: 0; }
  to { width: 100%; }
}

/* Individual date markers */
.colonial-timeline__marker {
  position: absolute;
  left: var(--marker-pos);
  top: 50%;
  transform: translate(-50%, -50%);
  display: flex;
  flex-direction: column;
  align-items: center;
  z-index: 2;
}

.colonial-timeline__dot {
  display: block;
  width: 14px;
  height: 14px;
  border-radius: 50%;
  background: var(--color-bg);
  border: 3px solid var(--color-sepia-mid);
  transition: border-color var(--duration-normal) var(--ease-out),
              background var(--duration-normal) var(--ease-out),
              transform var(--duration-normal) var(--ease-out);
  opacity: 0;
  transform: scale(0);
}

/* Staggered dot entrance: each marker appears after the progress bar reaches it */
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(2) .colonial-timeline__dot {
  animation: marker-pop 400ms var(--ease-out) 0.2s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(3) .colonial-timeline__dot {
  animation: marker-pop 400ms var(--ease-out) 0.55s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(4) .colonial-timeline__dot {
  animation: marker-pop 400ms var(--ease-out) 0.85s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(5) .colonial-timeline__dot {
  animation: marker-pop 400ms var(--ease-out) 1.1s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(6) .colonial-timeline__dot {
  animation: marker-pop 400ms var(--ease-out) 2.0s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(7) .colonial-timeline__dot {
  animation: marker-pop 400ms var(--ease-out) 2.3s forwards;
}

@keyframes marker-pop {
  0% {
    opacity: 0;
    transform: scale(0);
  }
  60% {
    opacity: 1;
    transform: scale(1.3);
  }
  100% {
    opacity: 1;
    transform: scale(1);
    background: var(--color-colonial);
    border-color: var(--color-colonial);
  }
}

/* Labels under dots */
.colonial-timeline__label {
  position: absolute;
  top: 1.2rem;
  left: 50%;
  transform: translateX(-50%);
  white-space: nowrap;
  font-family: var(--font-display);
  font-size: 0.72rem;
  font-weight: 700;
  line-height: 1.3;
  color: var(--color-text);
  text-align: center;
  opacity: 0;
}

.colonial-timeline__label small {
  display: block;
  font-family: var(--font-body);
  font-size: 0.62rem;
  font-weight: 400;
  color: var(--color-text-muted);
  white-space: nowrap;
}

/* Labels appear with dots */
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(2) .colonial-timeline__label {
  animation: label-fade 400ms var(--ease-out) 0.4s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(3) .colonial-timeline__label {
  animation: label-fade 400ms var(--ease-out) 0.75s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(4) .colonial-timeline__label {
  animation: label-fade 400ms var(--ease-out) 1.05s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(5) .colonial-timeline__label {
  animation: label-fade 400ms var(--ease-out) 1.3s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(6) .colonial-timeline__label {
  animation: label-fade 400ms var(--ease-out) 2.2s forwards;
}
.colonial-timeline.reveal--visible .colonial-timeline__marker:nth-child(7) .colonial-timeline__label {
  animation: label-fade 400ms var(--ease-out) 2.5s forwards;
}

@keyframes label-fade {
  from {
    opacity: 0;
    transform: translateX(-50%) translateY(4px);
  }
  to {
    opacity: 1;
    transform: translateX(-50%) translateY(0);
  }
}

/* Hover on markers */
.colonial-timeline__marker:hover .colonial-timeline__dot {
  border-color: var(--color-text) !important;
  transform: scale(1.3);
}

/* ---- Responsive: colonial timeline ---- */

@media (max-width: 48rem) {
  .colonial-timeline {
    margin: var(--space-xl) auto var(--space-md);
    padding: var(--space-lg) var(--space-md);
  }

  .colonial-timeline__track {
    margin: 2rem 0.5rem 3rem;
  }

  .colonial-timeline__label {
    font-size: 0.6rem;
  }

  .colonial-timeline__label small {
    font-size: 0.5rem;
  }

  .colonial-timeline__dot {
    width: 10px;
    height: 10px;
    border-width: 2px;
  }
}

@media (max-width: 30rem) {
  .colonial-timeline__label small {
    display: none;
  }

  .colonial-timeline__track {
    margin: 1.5rem 0 2.5rem;
  }
}

/* ---- Accessibility: skip timeline animations for reduced-motion users ---- */

@media (prefers-reduced-motion: reduce) {
  .colonial-timeline__progress {
    animation: none;
    width: 100%;
  }

  .colonial-timeline__dot {
    opacity: 1;
    transform: scale(1);
    animation: none !important;
    background: var(--color-colonial);
    border-color: var(--color-colonial);
  }

  .colonial-timeline__label {
    opacity: 1;
    transform: translateX(-50%);
    animation: none !important;
  }
}

